mapper.update:
UPDATE t_material_business_type
SET deleted_flag = #{deletedFlag}
WHERE business_type_id = #{businessTypeId}

mapper.select:
SELECT *
FROM t_material_business_type
WHERE business_type_code = #{businessTypeCode}
AND deleted_flag = #{deletedFlag}
and enterprise_id = #{enterpriseId}

    AND business_type_id != #{excludeBusinessTypeId}

SELECT *
FROM t_material_business_type
WHERE business_type_name = #{businessTypeName}
AND deleted_flag = #{deletedFlag}
and enterprise_id = #{enterpriseId}

    AND business_type_id != #{excludeBusinessTypeId}

SELECT bt.*
FROM t_material_business_type bt

    bt.deleted_flag = #{queryForm.deletedFlag}

        AND (INSTR(bt.business_type_name,#{queryForm.keywords})
        OR INSTR(bt.business_type_code,#{queryForm.keywords})
        OR INSTR(bt.create_user_name,#{queryForm.keywords}))


        AND bt.trip_type = #{queryForm.tripType}


        AND bt.enterprise_id = #{queryForm.enterpriseId}


        AND DATE_FORMAT(bt.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        AND DATE_FORMAT(bt.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        AND bt.disabled_flag = #{queryForm.disabledFlag}



    ORDER BY bt.create_time DESC

SELECT bt.*
FROM t_material_business_type bt
WHERE bt.business_type_id = #{businessTypeId}
  AND bt.deleted_flag = #{deletedFlag}

SELECT *
FROM t_material_business_type
WHERE default_flag = #{defaultFlag}
  AND deleted_flag = #{deletedFlag}
and enterprise_id = #{enterpriseId}

    AND business_type_id != #{excludeBusinessTypeId}

SELECT *
FROM t_material_business_type
WHERE deleted_flag = #{deletedFlag} AND disabled_flag = #{disabledFlag}
and enterprise_id = #{enterpriseId}
order by default_flag desc,business_type_id desc

SELECT *
FROM t_material_business_type
WHERE disabled_flag = #{disabledFlag}
AND deleted_flag = #{deletedFlag}
and enterprise_id = #{enterpriseId}
AND trim(business_type_name) in

    #{item}
